1	// game-of-life.spec.ts
2	import { describe, it, expect } from "vitest";
3	import { nextGeneration } from "./game-of-life.js";
4	
5	describe("Conway's Game of Life - Next Generation", () => {
6	  it("should return empty array for empty grid", () => {
7	    expect(nextGeneration([])).toEqual([]);
8	  });
9	  it("should kill a single live cell with no neighbors (underpopulation)", () => {
10	    expect(nextGeneration([[0, 0]])).toEqual([]);
11	  });
12	  it("should kill two adjacent live cells with only one neighbor each (underpopulation)", () => {
13	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
14	  });
15	  it("should keep alive a live cell with two live neighbors (survival)", () => {
16	    const result = nextGeneration([[0, 0], [1, 0], [2, 0]]);
17	    expect(result).toContainEqual([1, 0]);
18	  });
19	  it.todo("should keep alive a live cell with three live neighbors (survival)");
20	  it.todo("should kill a live cell with four live neighbors (overpopulation)");
21	  it.todo("should bring a dead cell to life when it has exactly three live neighbors (reproduction)");
22	  it.todo("should transform a vertical blinker into a horizontal blinker");
23	  it.todo("should keep a block unchanged across generations (still life)");
24	});
25

1	type Cell = [number, number];
2	
3	const areNeighbors = (a: Cell, b: Cell): boolean => {
4	  const [ax, ay] = a;
5	  const [bx, by] = b;
6	  if (ax === bx && ay === by) return false;
7	  return Math.abs(ax - bx) <= 1 && Math.abs(ay - by) <= 1;
8	};
9	
10	const countLiveNeighbors = (cell: Cell, liveCells: Cell[]): number =>
11	  liveCells.filter((other) => areNeighbors(cell, other)).length;
12	
13	const survives = (liveNeighbors: number): boolean =>
14	  liveNeighbors === 2 || liveNeighbors === 3;
15	
16	export const nextGeneration = (cells: Cell[]): Cell[] =>
17	  cells.filter((cell) => survives(countLiveNeighbors(cell, cells)));
